<?php
declare(strict_types=1);require __DIR__.'/bootstrap.php';use VP3\Sales\ProposalService;$customer=vp3_require_customer();$id=(int)vp3_input('id');$stmt=vp3_db()->prepare('SELECT * FROM proposals WHERE id=? AND customer_id=?');$stmt->execute([$id,$customer['id']]);$proposal=$stmt->fetch();if(!$proposal){http_response_code(404);exit('Proposal not found.');}
if($proposal['status']==='sent'){vp3_db()->prepare("UPDATE proposals SET status='viewed',viewed_at=COALESCE(viewed_at,NOW()),updated_at=NOW() WHERE id=?")->execute([$id]);$proposal['status']='viewed';}
if(vp3_method()==='POST'){vp3_verify_csrf();try{(new ProposalService(vp3_db()))->accept($id,(int)$customer['id'],vp3_input('accepted_name'),vp3_input('accepted_email'));vp3_flash('success','Proposal accepted. VP3 can now activate the project workspace.');}catch(Throwable $e){vp3_flash('error',str_replace('_',' ',$e->getMessage()));}vp3_redirect('account-proposal.php?id='.$id);}
$stmt=vp3_db()->prepare('SELECT * FROM proposal_items WHERE proposal_id=? ORDER BY sort_order,id');$stmt->execute([$id]);$items=$stmt->fetchAll();$stmt=vp3_db()->prepare('SELECT * FROM proposal_acceptances WHERE proposal_id=?');$stmt->execute([$id]);$acceptance=$stmt->fetch();$pageTitle=$proposal['title'];require VP3_ROOT.'/includes/account-header.php';?>
<div class="proposal-document"><header><div><span class="eyebrow">VP3 Media Group proposal</span><h1><?=vp3_e($proposal['title'])?></h1><p><?=vp3_e($proposal['summary'])?></p></div><div><strong><?=vp3_e($proposal['proposal_number'])?></strong><span class="badge <?=vp3_e($proposal['status'])?>"><?=vp3_e($proposal['status'])?></span><small>Valid until <?=vp3_e($proposal['valid_until']?:'open')?></small></div></header><section><h2>Scope</h2><p><?=nl2br(vp3_e($proposal['scope_text']))?></p></section><section><h2>Services and pricing</h2><div class="table-wrap"><table><thead><tr><th>Item</th><th>Billing</th><th>Quantity</th><th>Unit</th><th>Total</th></tr></thead><tbody><?php foreach($items as $item):?><tr><td><strong><?=vp3_e($item['name'])?></strong><br><small><?=vp3_e($item['description'])?></small></td><td><?=vp3_e(str_replace('_',' ',$item['billing_type']))?></td><td><?=vp3_e($item['quantity'])?></td><td><?=vp3_e(vp3_money((int)$item['unit_price_cents'],$proposal['currency']))?></td><td><?=vp3_e(vp3_money((int)$item['total_cents'],$proposal['currency']))?></td></tr><?php endforeach;?></tbody></table></div><div class="proposal-totals"><span>Subtotal <b><?=vp3_e(vp3_money((int)$proposal['subtotal_cents'],$proposal['currency']))?></b></span><span>Discount <b>−<?=vp3_e(vp3_money((int)$proposal['discount_cents'],$proposal['currency']))?></b></span><span>Tax <b><?=vp3_e(vp3_money((int)$proposal['tax_cents'],$proposal['currency']))?></b></span><strong>Total <b><?=vp3_e(vp3_money((int)$proposal['total_cents'],$proposal['currency']))?></b></strong><?php if((int)$proposal['deposit_cents']>0):?><span>Initial deposit <b><?=vp3_e(vp3_money((int)$proposal['deposit_cents'],$proposal['currency']))?></b></span><?php endif;?></div></section><section><h2>Terms</h2><p><?=nl2br(vp3_e($proposal['terms_text']))?></p></section><?php if($acceptance):?><div class="success-panel"><span>✓</span><h2>Accepted</h2><p>Accepted by <?=vp3_e($acceptance['accepted_name'])?> on <?=vp3_e($acceptance['accepted_at'])?>.</p></div><?php elseif(in_array($proposal['status'],['sent','viewed'],true)):?><form class="acceptance-card" method="post"><?=vp3_csrf_field()?><h2>Accept this proposal</h2><p>Acceptance records your identity, timestamp, terms version, and a one-way browser fingerprint hash for audit purposes.</p><div class="field"><label>Full name</label><input name="accepted_name" required value="<?=vp3_e($customer['name'])?>"></div><div class="field"><label>Email</label><input name="accepted_email" type="email" required value="<?=vp3_e($customer['email'])?>"></div><label class="check-row"><input type="checkbox" required> I accept the scope, pricing, delivery assumptions, and terms shown above.</label><button class="button">Accept proposal</button></form><?php endif;?></div>
<?php require VP3_ROOT.'/includes/account-footer.php'; ?>
